@if not private-typography-is-2014-config($config) {
  $args: (
    display-4: map.get($config, headline-1),
    display-3: map.get($config, headline-2),
    display-2: map.get($config, headline-3),
    display-1: map.get($config, headline-4),
    headline: map.get($config, headline-5),
    title: map.get($config, headline-6),
    subheading-2: map.get($config, subtitle-1),
    subheading-1: map.get($config, subtitle-2),
    body-2: map.get($config, body-1),
    body-1: map.get($config, body-2),
    button: map.get($config, button),
    caption: map.get($config, caption),
    font-family: map.get($config, font-family),
  );
  $non-null-args: ();
  @each $key, $value in $args {
    @if $value != null {
      $non-null-args: map.merge($non-null-args, ($key: $value));
    }
  }
  @return m2-typography.define-legacy-typography-config($non-null-args...);
}

@mixin hook-inverse-component-list(){

    .uk-list-muted > ::marker { color: $inverse-list-muted-color !important; }
    .uk-list-emphasis > ::marker { color: $inverse-list-emphasis-color !important; }
    .uk-list-primary > ::marker { color: $inverse-list-primary-color !important; }
    .uk-list-secondary > ::marker { color: $inverse-list-secondary-color !important; }

    .uk-list-bullet > ::before {
        @include svg-fill($internal-list-bullet-image, "#000", $inverse-list-bullet-icon-color);
    }

    .uk-list-divider > :nth-child(n+2) {
        border-top-color: $inverse-list-divider-border;
        @if(meta.mixin-exists(hook-inverse-list-divider)) {@include hook-inverse-list-divider();}
    }

    .uk-list-striped > * {
        @if(meta.mixin-exists(hook-inverse-list-striped)) {@include hook-inverse-list-striped();}
    }

    .uk-list-striped > :nth-of-type(odd) { background-color: $inverse-list-striped-background; }

}

&[disabled] {
  cursor: not-allowed;
  user-select: none;

  ~ label .slds-visual-picker__body,
  ~ label .slds-visual-picker__text {
    color: var(--slds-g-color-neutral-base-50, #{$color-text-input-disabled});
  }

  ~ label .slds-visual-picker__figure {
    border-color: var(--slds-g-color-border-base-1, #{$color-border-input-disabled});
    background-color: var(--slds-g-color-neutral-base-95, #{$color-background-input-disabled});
    box-shadow: none;

    &:hover {
      cursor: not-allowed;
      user-select: none;
      box-shadow: none;
    }
  }

  ~label .slds-visual-picker__figure .slds-icon {
    fill: var(--slds-g-color-neutral-base-80, #{$color-text-icon-default-disabled});
  }

}

@mixin button-outline-variant(
  $color,
  $color-hover: color-contrast($color),
  $active-background: $color,
  $active-border: $color,
  $active-color: color-contrast($active-background)
) {
  --#{$prefix}btn-color: #{$color};
  --#{$prefix}btn-border-color: #{$color};
  --#{$prefix}btn-hover-color: #{$color-hover};
  --#{$prefix}btn-hover-bg: #{$active-background};
  --#{$prefix}btn-hover-border-color: #{$active-border};
  --#{$prefix}btn-focus-shadow-rgb: #{to-rgb($color)};
  --#{$prefix}btn-active-color: #{$active-color};
  --#{$prefix}btn-active-bg: #{$active-background};
  --#{$prefix}btn-active-border-color: #{$active-border};
  --#{$prefix}btn-active-shadow: #{$btn-active-box-shadow};
  --#{$prefix}btn-disabled-color: #{$color};
  --#{$prefix}btn-disabled-bg: transparent;
  --#{$prefix}btn-disabled-border-color: #{$color};
  --#{$prefix}gradient: none;
}
// scss-docs-end btn-outline-variant-mixin

input[data-invalid],
  .#{$prefix}--number[data-invalid] .#{$prefix}--number__input-wrapper,
  .#{$prefix}--number__input-wrapper--warning,
  .#{$prefix}--date-picker-input__wrapper,
  .#{$prefix}--date-picker-input__wrapper--warn,
  .#{$prefix}--date-picker-input__wrapper--invalid,
  .#{$prefix}--time-picker--invalid,
  .#{$prefix}--time-picker--warning,
  .#{$prefix}--text-input__field-wrapper[data-invalid],
  .#{$prefix}--text-input__field-wrapper--warning,
  .#{$prefix}--text-input__field-wrapper--warning > .#{$prefix}--text-input,
  .#{$prefix}--text-area__wrapper[data-invalid],
  .#{$prefix}--text-area__wrapper--warn,
  .#{$prefix}--select-input__wrapper[data-invalid],
  .#{$prefix}--select--warning .#{$prefix}--select-input__wrapper,
  .#{$prefix}--time-picker[data-invalid],
  .#{$prefix}--list-box[data-invalid],
  .#{$prefix}--list-box--warning {
    ~ .#{$prefix}--form-requirement {
      display: block;
      overflow: visible;
      font-weight: 400;
      max-block-size: convert.to-rem(200px);
    }
  }
